import logging
import os
import re

import azure.functions as func
from azure.storage.blob import BlobServiceClient
from azure.core.exceptions import ResourceNotFoundError, HttpResponseError


def validate_blob_path(blob_path: str) -> bool:
    """Validate blob path to prevent path traversal and other attacks."""
    if not blob_path:
        return False
    
    if '..' in blob_path:
        return False
    
    if blob_path.startswith('/') or blob_path.startswith('\\'):
        return False
    
    if re.search(r'[<>"|?*\x00-\x1f]', blob_path):
        return False
    
    if len(blob_path) > 1024:
        return False
    
    normalized = os.path.normpath(blob_path).replace('\\', '/')
    if normalized.startswith('..') or normalized.startswith('/'):
        return False
    
    return True


ALLOWED_CONTENT_TYPES = {
    '.txt': 'text/plain',
    '.json': 'application/json',
    '.csv': 'text/csv',
    '.xml': 'application/xml',
    '.html': 'text/html',
    '.pdf': 'application/pdf',
    '.png': 'image/png',
    '.jpg': 'image/jpeg',
    '.jpeg': 'image/jpeg',
    '.gif': 'image/gif',
    '.svg': 'image/svg+xml',
    '.css': 'text/css',
    '.js': 'application/javascript',
    '.yaml': 'application/x-yaml',
    '.yml': 'application/x-yaml',
    '.md': 'text/markdown',
    '.zip': 'application/zip',
}

MAX_FILE_SIZE = 50 * 1024 * 1024  # 50 MB


def get_content_type(blob_path: str) -> str:
    """Determine content type based on file extension."""
    _, ext = os.path.splitext(blob_path.lower())
    return ALLOWED_CONTENT_TYPES.get(ext, 'application/octet-stream')


def main(req: func.HttpRequest) -> func.HttpResponse:
    logging.info('File serving API triggered.')

    blob_path = req.params.get('path')

    if not blob_path:
        return func.HttpResponse(
            '{"error": "Missing required query parameter: path"}',
            status_code=400,
            mimetype='application/json'
        )

    blob_path = blob_path.strip()

    if not validate_blob_path(blob_path):
        logging.warning(f'Invalid blob path requested: {blob_path}')
        return func.HttpResponse(
            '{"error": "Invalid blob path"}',
            status_code=400,
            mimetype='application/json'
        )

    _, ext = os.path.splitext(blob_path.lower())
    if ext and ext not in ALLOWED_CONTENT_TYPES:
        logging.warning(f'Disallowed file extension requested: {ext}')
        return func.HttpResponse(
            '{"error": "File type not allowed"}',
            status_code=403,
            mimetype='application/json'
        )

    connection_string = os.environ.get('AZURE_STORAGE_CONNECTION_STRING')
    container_name = os.environ.get('BLOB_CONTAINER_NAME')

    if not connection_string or not container_name:
        logging.error('Missing storage configuration environment variables.')
        return func.HttpResponse(
            '{"error": "Server configuration error"}',
            status_code=500,
            mimetype='application/json'
        )

    try:
        blob_service_client = BlobServiceClient.from_connection_string(connection_string)
        blob_client = blob_service_client.get_blob_client(
            container=container_name,
            blob=blob_path
        )

        blob_properties = blob_client.get_blob_properties()

        if blob_properties.size > MAX_FILE_SIZE:
            logging.warning(f'Blob too large: {blob_path} ({blob_properties.size} bytes)')
            return func.HttpResponse(
                '{"error": "File too large to serve"}',
                status_code=413,
                mimetype='application/json'
            )

        blob_data = blob_client.download_blob()
        content = blob_data.readall()

        content_type = get_content_type(blob_path)

        filename = os.path.basename(blob_path)
        safe_filename = re.sub(r'[^\w\.\-]', '_', filename)

        headers = {
            'Content-Type': content_type,
            'Content-Disposition': f'inline; filename="{safe_filename}"',
            'X-Content-Type-Options': 'nosniff',
            'Cache-Control': 'private, max-age=300',
        }

        logging.info(f'Successfully served blob: {blob_path} ({len(content)} bytes)')

        return func.HttpResponse(
            body=content,
            status_code=200,
            headers=headers,
            mimetype=content_type
        )

    except ResourceNotFoundError:
        logging.info(f'Blob not found: {blob_path}')
        return func.HttpResponse(
            '{"error": "File not found"}',
            status_code=404,
            mimetype='application/json'
        )

    except HttpResponseError as e:
        logging.error(f'Azure Storage HTTP error for blob {blob_path}: {e.message}')
        return func.HttpResponse(
            '{"error": "Storage service error"}',
            status_code=502,
            mimetype='application/json'
        )

    except ValueError as e:
        logging.error(f'Value error: {str(e)}')
        return func.HttpResponse(
            '{"error": "Invalid request"}',
            status_code=400,
            mimetype='application/json'
        )

    except Exception as e:
        logging.error(f'Unexpected error serving blob {blob_path}: {type(e).__name__}')
        return func.HttpResponse(
            '{"error": "Internal server error"}',
            status_code=500,
            mimetype='application/json'
        )